    result = process_payment(enterprise_user, cart, payment)
    print(f"Cart Total: ${result['cart_total']}")
    print(f"Discount: {result['discount_percentage']}% (-${result['discount_amount']})")
    print(f"Final Total: ${result['final_total']}")
    print(f"Transaction Status: {result['transaction']['status']}")
    print(f"Transaction ID: {result['transaction']['transaction_id']}")
    print()

    print("=== Premium User ===")
    result = process_payment(premium_user, cart, payment)
    print(f"Cart Total: ${result['cart_total']}")
    print(f"Discount: {result['discount_percentage']}% (-${result['discount_amount']})")
    print(f"Final Total: ${result['final_total']}")
    print(f"Transaction Status: {result['transaction']['status']}")
    print()

    print("=== Basic User ===")
